import { defineConfig } from "tsdown";

// @bench/hono-app build: bundle the modular src (app + route groups) into ONE
// self-contained dist/index.js + dist/index.d.ts, consumed identically by the
// three Hono runtime entries. The .d.ts is generated by oxc isolated-declarations
// (`dts: { oxc: true }`) — NOT the TS compiler API, which the TS 7.0.1-rc does
// not expose (plain `dts: true` fails on the RC; see PLAN §4 / typescript.md
// rule 40). Revisit full dts mode when TS 7.1 restores the programmatic API.
export default defineConfig({
  entry: "src/index.ts",
  outDir: "dist",
  format: "esm",
  platform: "neutral",
  target: "es2024",
  dts: { oxc: true },
  sourcemap: false,
  clean: true,
  treeshake: true,
  // The real runtime deps stay external (imports preserved in the bundle), so
  // every consumer resolves them from the workspace node_modules. `neverBundle`
  // is the non-deprecated form of the old `external` option; the hono regex
  // covers its subpath entries (hono/body-limit, hono/cookie, hono/logger).
  deps: {
    neverBundle: [/^hono(\/.*)?$/, "@bench/shared"]
  }
});
